// ============================================
// BULK OPERATIONS
// ============================================

// Bulk Create
router.post(
  '/bulk/create',
  authenticateToken,
  [
    body('items').isArray({ min: 1 }).withMessage('Must provide array of items'),
    validateErrors
  ],
  async (req, res, next) => {
    try {
      const items = await __MODEL_NAME__.insertMany(req.body.items, { ordered: false });

      res.status(201).json({
        success: true,
        message: `Created ${items.length} records`,
        count: items.length,
        data: items
      });
    } catch (error) {
      next(error);
    }
  }
);

// Bulk Delete
router.delete(
  '/bulk/delete',
  authenticateToken,
  [
    body('ids').isArray({ min: 1 }).withMessage('Must provide array of IDs'),
    validateErrors
  ],
  async (req, res, next) => {
    try {
      const result = await __MODEL_NAME__.deleteMany({
        _id: { $in: req.body.ids }
      });

      res.status(200).json({
        success: true,
        message: `Deleted ${result.deletedCount} records`,
        deletedCount: result.deletedCount
      });
    } catch (error) {
      next(error);
    }
  }
);

// Bulk Update
router.put(
  '/bulk/update',
  [
    body('updates').isArray().withMessage('Must provide array of updates'),
    validateErrors
  ],
  async (req, res, next) => {
    try {
      const bulkOps = req.body.updates.map(update => ({
        updateOne: {
          filter: { _id: update.id },
          update: { $set: update.data },
          upsert: false
        }
      }));

      const result = await __MODEL_NAME__.bulkWrite(bulkOps);

      res.status(200).json({
        success: true,
        message: 'Bulk update completed',
        modifiedCount: result.modifiedCount,
        matchedCount: result.matchedCount
      });
    } catch (error) {
      next(error);
    }
  }
);

